import { createApp } from 'vue';
import App from './App.vue';

$(() => {
  const raw = (window as any).__thoughts__ ?? { name: '???', content: '' };
  const app = createApp(App, { name: raw.name as string, content: raw.content as string });
  app.mount('#app');
  $(window).on('pagehide', () => app.unmount());
});
